from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects describing an artist (or related entity)
    into a single fluent English sentence, merging information wherever possible.
    """
    if not triples:
        return ""

    # Determine the main subject – the subject that appears most often
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get)

    # Group triples by subject
    from collections import defaultdict
    grouped = defaultdict(list)
    for t in triples:
        grouped[t.subject].append(t)

    # Helper to produce a phrase for a predicate/object of the main subject
    def main_phrase(p: str, objs):
        # format list of objects
        def fmt(lst):
            if len(lst) == 1:
                return lst[0]
            return ", ".join(lst[:-1]) + " and " + lst[-1]

        obj_str = fmt(objs)

        if p in ("associatedBand/associatedMusicalArtist",):
            return f"has been a member of {obj_str}"
        if p == "background":
            return f"is a {obj_str}"
        if p == "genre":
            return f"plays {obj_str.lower()} music"
        if p == "instrument":
            return f"plays the {obj_str}"
        if p == "origin":
            return f"is from {obj_str}"
        if p == "birthDate":
            return f"was born on {obj_str}"
        if p == "birthPlace":
            return f"was born in {obj_str}"
        if p == "birthYear":
            return f"was born in {obj_str}"
        if p == "occupation":
            return f"is a {obj_str}"
        if p == "recordLabel":
            return f"is signed to {obj_str}"
        if p == "deathPlace":
            return f"died in {obj_str}"
        if p == "deathDate":
            return f"died on {obj_str}"
        if p == "nationality":
            return f"is {obj_str}"
        if p == "professionalField":
            return f"works in {obj_str}"
        if p in ("language", "officialLanguage"):
            return f"speaks {obj_str}"
        if p == "activeYearsStartYear":
            return f"started in {obj_str}"
        if p == "activeYearsEndYear":
            return f"ended in {obj_str}"
        # default fallback
        pred_readable = p.replace("_", " ")
        return f"{pred_readable} {obj_str}"

    # Build phrases for the main subject
    main_phrases = []
    for pred, objs in defaultdict(list, {t.predicate: [] for t in grouped[main_subject]}).items():
        # collect objects for this predicate
        objs = [t.object.strip('"') for t in grouped[main_subject] if t.predicate == pred]
        if not objs:
            continue
        main_phrases.append(main_phrase(pred, objs))

    # Assemble the main clause
    if main_phrases:
        if len(main_phrases) == 1:
            main_clause = f"{main_subject} {main_phrases[0]}."
        else:
            body = ", ".join(main_phrases[:-1]) + ", and " + main_phrases[-1]
            main_clause = f"{main_subject} {body}."
    else:
        main_clause = ""

    # Generate sentences for secondary subjects
    secondary_sentences = []
    for subj, triples_list in grouped.items():
        if subj == main_subject:
            continue
        for t in triples_list:
            obj = t.object.strip('"')
            p = t.predicate
            if p == "parentCompany":
                secondary_sentences.append(f"{obj} is the parent company of {subj}.")
            elif p == "musicFusionGenre":
                secondary_sentences.append(f"{obj} is a fusion genre that incorporates {subj.lower()}.")
            elif p == "derivative":
                secondary_sentences.append(f"{obj} is derived from {subj.lower()}.")
            elif p == "bandMember":
                secondary_sentences.append(f"{obj} is a member of {subj}.")
            elif p == "capital":
                secondary_sentences.append(f"The capital of {subj} is {obj}.")
            elif p == "currency":
                secondary_sentences.append(f"The currency of {subj} is {obj}.")
            elif p == "anthem":
                secondary_sentences.append(f"The anthem of {subj} is {obj}.")
            elif p == "demonym":
                secondary_sentences.append(f"The demonym for {subj} is {obj}.")
            elif p in ("language", "officialLanguage"):
                secondary_sentences.append(f"The official language of {subj} is {obj}.")
            else:
                pred_readable = p.replace("_", " ")
                secondary_sentences.append(f"The {pred_readable} of {subj} is {obj}.")

    # Combine all parts
    parts = [s for s in [main_clause] + secondary_sentences if s]
    return " ".join(parts)

# EVOLVE-BLOCK-END

